function i(t,o=Date.now()){if(!t)return"—";const n=Date.parse(t);if(Number.isNaN(n))return"—";const f=Math.floor(Math.max(0,o-n)/1e3);if(f<60)return"just now";const e=Math.floor(f/60);if(e<60)return`${e}m ago`;const a=Math.floor(e/60);if(a<24)return`${a}h ago`;const r=Math.floor(a/24);if(r<30)return`${r}d ago`;const u=Math.floor(r/30);return r<365?`${u}mo ago`:`${Math.floor(r/365)}y ago`}function s(t){if(!t)return"—";const o=Date.parse(t);return Number.isNaN(o)?"—":new Date(o).toLocaleString()}export{s as f,i as r};
